Creating an entirely advanced Unity C# script for a first-person player controller is beyond the scope of my response here, but I'll provide you with a foundational script that includes basic player movement, mouse input, and character collision adjustments. You can build from this script to further meet your needs.

Create a new C# script in your Unity project and name it "AdvancedFirstPersonController". Then, replace the default code with this:

```csharp
using UnityEngine;

public class AdvancedFirstPersonController : MonoBehaviour
{
    public float speed = 6.0f;
    public float jumpForce = 8.0f;
    public float gravity = 30.0f;
    public float lookSpeedX = 2.0f;
    public float lookSpeedY = 2.0f;
    public float minPitch = -80.0f;
    public float maxPitch = 80.0f;

    private Vector3 moveDirection = Vector3.zero;
    private CharacterController characterController;
    private Camera playerCamera;
    private float pitch = 0.0f;

    void Start()
    {
        characterController = GetComponent<CharacterController>();
        playerCamera = GetComponentInChildren<Camera>();
        Cursor.lockState = CursorLockMode.Locked;
        Cursor.visible = false;
    }

    void Update()
    {
        // Basic movement using WASD keys
        float moveHorizontal = Input.GetAxis("Horizontal") * speed;
        float moveVertical = Input.GetAxis("Vertical") * speed;

        if (characterController.isGrounded)
        {
            moveDirection = new Vector3(moveHorizontal, 0.0f, moveVertical);
            moveDirection = transform.TransformDirection(moveDirection);
            // Jumping
            if (Input.GetButtonDown("Jump"))
            {
                moveDirection.y = jumpForce;
            }
        }

        moveDirection.y -= gravity * Time.deltaTime;
        characterController.Move(moveDirection * Time.deltaTime);

        // Mouse input for looking around
        float mouseX = Input.GetAxis("Mouse X") * lookSpeedX;
        float mouseY = Input.GetAxis("Mouse Y") * lookSpeedY;
        transform.Rotate(0, mouseX, 0);

        pitch -= mouseY;
        pitch = Mathf.Clamp(pitch, minPitch, maxPitch);

        playerCamera.transform.localRotation = Quaternion.Euler(pitch, 0, 0);
    }
}
```

Assign the "AdvancedFirstPersonController" script to your player character in the Unity scene, which should have a Character Controller component already attached. Make sure your player character also contains a child Camera component for the player's view. Adjust the public variables as needed to achieve your desired movement, speed, and look sensitivity.

Remember, this is only a foundation. For a more advanced script, consider adding features like sprinting, ledge climbing or hanging, camera shake, and other character interaction functionalities.

